import{_ as t,o as r,c as a,ag as o}from"./chunks/framework.OsDJF_Ea.js";const u=JSON.parse('{"title":"API Keys","description":"","frontmatter":{},"headers":[],"relativePath":"guide/api-keys.md","filePath":"guide/api-keys.md"}'),s={name:"guide/api-keys.md"};function d(i,e,n,l,h,c){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="api-keys" tabindex="-1">API Keys <a class="header-anchor" href="#api-keys" aria-label="Permalink to &quot;API Keys&quot;">​</a></h1><p>Most of InspoSearch&#39;s 500+ sources work without authentication. <strong>13 sources</strong> require an API key. Keys are stored in your browser&#39;s <code>localStorage</code> and are sent only to the respective API provider.</p><h2 id="sources-requiring-keys" tabindex="-1">Sources Requiring Keys <a class="header-anchor" href="#sources-requiring-keys" aria-label="Permalink to &quot;Sources Requiring Keys&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>Category</th><th>Where to Get a Key</th></tr></thead><tbody><tr><td>Rijksmuseum</td><td>Museums</td><td><a href="https://www.rijksmuseum.nl/en/rijksstudio" target="_blank" rel="noreferrer">rijksmuseum.nl/en/rijksstudio</a> — free account</td></tr><tr><td>Harvard Art Museums</td><td>Museums</td><td><a href="https://harvardartmuseums.org/collections/api" target="_blank" rel="noreferrer">harvardartmuseums.org/collections/api</a> — request access</td></tr><tr><td>Cooper Hewitt, Smithsonian</td><td>Museums</td><td><a href="https://collection.cooperhewitt.org/api/" target="_blank" rel="noreferrer">collection.cooperhewitt.org/api</a> — create a token</td></tr><tr><td>Europeana</td><td>Historical</td><td><a href="https://pro.europeana.eu/page/get-api" target="_blank" rel="noreferrer">pro.europeana.eu/page/get-api</a> — free registration</td></tr><tr><td>Digital Public Library of America</td><td>Historical</td><td><a href="https://dp.la/info/developers/codex" target="_blank" rel="noreferrer">dp.la/info/developers/codex</a> — request a key</td></tr><tr><td>National Library of Australia (Trove)</td><td>Historical</td><td><a href="https://trove.nla.gov.au/about/create-something/using-api" target="_blank" rel="noreferrer">trove.nla.gov.au/about/create-something/using-api</a> — free sign-up</td></tr><tr><td>Unsplash</td><td>Photography</td><td><a href="https://unsplash.com/developers" target="_blank" rel="noreferrer">unsplash.com/developers</a> — register an app</td></tr><tr><td>Flickr</td><td>Photography</td><td><a href="https://www.flickr.com/services/api/" target="_blank" rel="noreferrer">flickr.com/services/api</a> — apply for a key</td></tr><tr><td>Pixabay</td><td>Photography</td><td><a href="https://pixabay.com/api/docs/" target="_blank" rel="noreferrer">pixabay.com/api/docs</a> — free API key</td></tr><tr><td>Pexels</td><td>Photography</td><td><a href="https://www.pexels.com/api/" target="_blank" rel="noreferrer">pexels.com/api</a> — free sign-up</td></tr><tr><td>Noun Project</td><td>Art and Design</td><td><a href="https://thenounproject.com/developers/" target="_blank" rel="noreferrer">thenounproject.com/developers</a> — register an app</td></tr><tr><td>YouTube (thumbnails)</td><td>Science</td><td><a href="https://console.cloud.google.com/" target="_blank" rel="noreferrer">console.cloud.google.com</a> — enable YouTube Data API v3</td></tr><tr><td>Giphy</td><td>Art and Design</td><td><a href="https://developers.giphy.com/" target="_blank" rel="noreferrer">developers.giphy.com</a> — create an app</td></tr></tbody></table><h2 id="how-to-add-a-key" tabindex="-1">How to Add a Key <a class="header-anchor" href="#how-to-add-a-key" aria-label="Permalink to &quot;How to Add a Key&quot;">​</a></h2><ol><li>Open <a href="https://insposearch.pages.dev" target="_blank" rel="noreferrer">InspoSearch</a></li><li>Press <code>k</code> or click the Keys icon in the toolbar to open the Keys panel</li><li>Find the source in the list</li><li>Paste your API key into the input field</li><li>The key saves to <code>localStorage</code> immediately — no submit button</li><li>Close the panel and search. Results from that source will now appear</li></ol><h2 id="key-storage-and-privacy" tabindex="-1">Key Storage and Privacy <a class="header-anchor" href="#key-storage-and-privacy" aria-label="Permalink to &quot;Key Storage and Privacy&quot;">​</a></h2><p>Keys are stored only in your browser&#39;s <code>localStorage</code>. They are sent only to the respective API endpoint — your Rijksmuseum key goes only to <code>api.rijksmuseum.nl</code>, for example. InspoSearch has no backend server and there is nowhere for keys to be forwarded. Clearing your browser data removes stored keys. You can remove a key at any time by clearing the field in the Keys panel.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Issue</th><th>Solution</th></tr></thead><tbody><tr><td>Source still shows no results after adding key</td><td>Verify the key is valid by testing the API URL directly in your browser</td></tr><tr><td>Key disappeared</td><td>Browser data was cleared — re-enter the key</td></tr><tr><td>Unauthorized errors in console</td><td>The key may have expired or been revoked — generate a new one</td></tr><tr><td>Rate limit errors</td><td>Some APIs have daily limits on free keys — wait and retry later</td></tr></tbody></table>',10)])])}const y=t(s,[["render",d]]);export{u as __pageData,y as default};
